import { useState, useEffect } from "react";

var MX = [
  "",
  "",
  "",
  "",
  "",
].join("");
var RB = [
  "",
  "",
  "",
  "",
  "",
].join("");
var RM = [
  "",
  "",
  "",
  "",
  "",
].join("");

var FONTS_LOADED = false;
function loadFonts() {
  if (FONTS_LOADED) return;
  FONTS_LOADED = true;
  var s = document.createElement("style");
  s.textContent = "@font-face{font-family:Maxeville;src:url(data:font/woff2;base64," + MX + ") format(woff2)}@font-face{font-family:Relative;src:url(data:font/woff2;base64," + RB + ") format(woff2)}@font-face{font-family:RelativeMono;src:url(data:font/woff2;base64," + RM + ") format(woff2)}";
  document.head.appendChild(s);
}

var metrics = [
  { value: 59, label: "Women", sublabel: "of total headcount", color: "#016F4F", track: "#E8F5F0" },
  { value: 72, label: "In Leadership", sublabel: "women in leadership positions", color: "#DFFF56", track: "#F7FFD6" },
  { value: 41, label: "Female Founder", sublabel: "companies with at least one female founder", color: "#0B261E", track: "#E8EAE9" },
];

var BASE_SIZE = 190;
var HOVER_SIZE = 220;
var STROKE = 14;

function Ring(props) {
  var metric = props.metric;
  var animate = props.animate;
  var hState = useState(false);
  var hovered = hState[0];
  var setHovered = hState[1];

  var size = hovered ? HOVER_SIZE : BASE_SIZE;
  var r = (size / 2) - STROKE - 2;
  var circ = 2 * Math.PI * r;
  var dash = animate ? (metric.value / 100) * circ : 0;
  var gap = circ - dash;

  return (
    <div
      onMouseEnter={function() { setHovered(true); }}
      onMouseLeave={function() { setHovered(false); }}
      style={{ display:"flex", flexDirection:"column", alignItems:"center", flex:1, cursor:"default" }}
    >
      <div style={{ position:"relative", width:size, height:size, transition:"width 0.3s cubic-bezier(0.16,1,0.3,1), height 0.3s cubic-bezier(0.16,1,0.3,1)" }}>
        <svg width={size} height={size} style={{ transform:"rotate(-90deg)", display:"block" }}>
          <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={metric.track} strokeWidth={hovered ? STROKE+2 : STROKE} style={{ transition:"stroke-width 0.3s" }} />
          <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={metric.color} strokeWidth={hovered ? STROKE+2 : STROKE}
            strokeDasharray={dash + " " + gap} strokeLinecap="round"
            style={{ transition:"stroke-dasharray 1.3s cubic-bezier(0.16,1,0.3,1), stroke-width 0.3s" }} />
        </svg>
        <div style={{ position:"absolute", top:0, left:0, right:0, bottom:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <span style={{ fontFamily:"Maxeville", fontSize: hovered ? 46 : 40, color:"#0B261E", letterSpacing:"-0.03em", lineHeight:1, transition:"font-size 0.3s" }}>
            {metric.value}%
          </span>
        </div>
      </div>

      <div style={{ marginTop:18, textAlign:"center" }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:8, marginBottom:6 }}>
          <span style={{
            display:"inline-block",
            width: hovered ? 28 : 10,
            height: 10,
            borderRadius: 20,
            background: metric.color,
            border: metric.color === "#DFFF56" ? "1px solid #d0e040" : "none",
            transition: "width 0.3s cubic-bezier(0.16,1,0.3,1)",
            flexShrink: 0,
          }} />
          <span style={{ fontFamily:"RelativeMono", fontSize:14, letterSpacing:"0.08em", textTransform:"uppercase", color:"#0B261E", fontWeight:700 }}>
            {metric.label}
          </span>
        </div>
        <p style={{ fontFamily:"RelativeMono", fontSize:10, letterSpacing:"0.07em", color:"#0B261E", opacity: hovered ? 0.7 : 0.4, margin:0, transition:"opacity 0.2s", textTransform:"uppercase", maxWidth:160, lineHeight:1.5 }}>
          {metric.sublabel}
        </p>
      </div>
    </div>
  );
}

export default function GenderDiversity() {
  useEffect(function() { loadFonts(); }, []);
  var aState = useState(false);
  var animate = aState[0];
  var setAnimate = aState[1];

  useEffect(function() {
    var t = setTimeout(function() { setAnimate(true); }, 300);
    return function() { clearTimeout(t); };
  }, []);

  return (
    <div style={{ background:"#FFFFFF", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", padding:"48px 32px", boxSizing:"border-box" }}>
      <div style={{ width:"100%", maxWidth:780 }}>

        <div style={{ textAlign:"center", marginBottom:44, paddingBottom:28, borderBottom:"1px solid rgba(11,38,30,0.1)" }}>
          <p style={{ fontFamily:"RelativeMono", fontSize:11, letterSpacing:"0.2em", textTransform:"uppercase", color:"#0B261E", opacity:0.45, margin:"0 0 8px" }}>
            + Total Portfolio Headcount +
          </p>
          <span style={{ fontFamily:"Maxeville", fontSize:64, color:"#0B261E", letterSpacing:"-0.03em", lineHeight:1 }}>
            {"1,091"}
          </span>
          <p style={{ fontFamily:"RelativeMono", fontSize:11, letterSpacing:"0.12em", textTransform:"uppercase", color:"#0B261E", opacity:0.4, margin:"10px 0 0" }}>
            People across the portfolio
          </p>
        </div>

        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"center", gap:0 }}>
          {metrics.map(function(metric, i) {
            return (
              <div key={i} style={{ display:"flex", alignItems:"center", flex:1 }}>
                <Ring metric={metric} animate={animate} />
                {i < metrics.length - 1 && (
                  <span style={{ fontFamily:"RelativeMono", fontSize:24, color:"#0B261E", opacity:0.12, flexShrink:0, marginTop:-60 }}>+</span>
                )}
              </div>
            );
          })}
        </div>

      </div>
    </div>
  );
}